final:
module RefModule(
	input clk,
	input rst_n,
	output sink_sop,
	output sink_eop
);reg [10:0] unused_counter;

always@(posedge clk)
if(!rst_n)
	unused_counter<=11'd0;
else if(unused_counter>=11'd1030)
	unused_counter<=11'd0;
else
	unused_counter<=unused_counter+1'b1;


assign sink_sop=(unused_counter==11'd0)?1'b1:1'b0;

assign sink_eop=(unused_counter==11'd1023)?1'b1:1'b0;

endmodule
